mapper.select:

SELECT *
FROM 
	APP_SCOPE
WHERE
	ENABLED_FLAG=1			


AND ID=#{id}


AND upper(NAME) like upper('%${name}%')


AND TYPE=#{type}


AND STATUS=#{status}


AND LAST_UPDATE_DATE=#{lastUpdateDate}


AND LAST_UPDATED_BY=#{lastUpdatedBy}


AND CREATION_DATE=#{creationDate}


AND CREATED_BY=#{createdBy}

ORDER BY ID


SELECT 
	*
FROM 
	APP_SCOPE
WHERE
	ENABLED_FLAG=1				


AND ID=#{bo.id}


AND upper(NAME) like upper('%${bo.name}%')


AND TYPE=#{bo.type}


AND TYPE !='SIMULATION' AND TYPE !='ENROL'


AND STATUS=#{status}


AND LAST_UPDATE_DATE=#{lastUpdateDate}


AND LAST_UPDATED_BY=#{lastUpdatedBy}


AND CREATION_DATE=#{creationDate}


AND CREATED_BY=#{createdBy}

ORDER BY ${page.sortFieldName} DESC
